import { Passkeys } from "@laravel/passkeys";
import { useState } from "react";
import InputError from "@/components/input-error";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useErrorToast } from "@/hooks/use-error-toast";
import { useActionConfirmation } from "@/components/action-confirmation-provider";

type Props = {
    onSuccess: () => void;
};

const isActionConfirmationCancelled = (error: unknown): boolean => {
    return error instanceof Error && error.name === "ActionConfirmationCancelledError";
};

export default function PasskeyRegistration({ onSuccess }: Props) {
    const { confirmSensitiveAction } = useActionConfirmation();
    const [name, setName] = useState(() => {
        const ua = navigator.userAgent;

        const browser = [
            { pattern: /Edg|Edge/, name: "Edge" },
            { pattern: /OPR|Opera|OPiOS/, name: "Opera" },
            { pattern: /Firefox|FxiOS/, name: "Firefox" },
            { pattern: /Chrome|CriOS/, name: "Chrome" },
            { pattern: /Safari/, name: "Safari" },
        ].find(({ pattern }) => pattern.test(ua))?.name;

        const os = [
            { pattern: /iPhone/, name: "iPhone" },
            { pattern: /iPad|Macintosh(?=.*Mobile)/, name: "iPad" },
            { pattern: /Android/, name: "Android" },
            { pattern: /Mac/, name: "Mac" },
            { pattern: /Windows/, name: "Windows" },
        ].find(({ pattern }) => pattern.test(ua))?.name;

        return [browser, os].filter(Boolean).join(" on ") || "";
    });

    const [showForm, setShowForm] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const isSupported = Passkeys.isSupported();

    useErrorToast(error);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!name.trim()) {
            return;
        }

        setIsLoading(true);
        setError(null);

        try {
            await confirmSensitiveAction(() => Passkeys.register({ name }));
            setName("");
            setShowForm(false);
            onSuccess();
        } catch (error) {
            if (!isActionConfirmationCancelled(error)) {
                setError(error instanceof Error ? error.message : "Unable to register passkey.");
            }
        } finally {
            setIsLoading(false);
        }
    };

    const handleCancel = () => {
        setShowForm(false);
        setName("");
        setError(null);
    };

    if (!isSupported) {
        return (
            <div className="text-sm text-muted-foreground">
                Passkeys are not supported in this browser.
            </div>
        );
    }

    if (!showForm) {
        return (
            <Button variant="outline" onClick={() => setShowForm(true)}>
                Add passkey
            </Button>
        );
    }

    return (
        <form
            onSubmit={handleSubmit}
            className="space-y-4 rounded-lg border border-border bg-muted/50 p-4"
        >
            <div className="grid gap-2">
                <Label htmlFor="passkey-name">Passkey name</Label>
                <Input
                    id="passkey-name"
                    type="text"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    placeholder="e.g., MacBook Pro, iPhone"
                    className="mt-1 block w-full border-foreground/20"
                    autoFocus
                />
                <p className="text-xs text-muted-foreground">
                    A name helps you identify this passkey later.
                </p>
            </div>

            {error && <InputError message={error} />}

            <div className="flex gap-2">
                <Button type="submit" disabled={isLoading || !name.trim()}>
                    {isLoading ? "Registering..." : "Register passkey"}
                </Button>
                <Button type="button" variant="ghost" onClick={handleCancel}>
                    Cancel
                </Button>
            </div>
        </form>
    );
}
